import React, { useState, useEffect } from 'react';
import { supabase } from './supabaseClient'; // Importando nossa conexão!

function App() {
  const [view, setView] = useState('home');
  const [campeonatos, setCampeonatos] = useState([]);

  const [nome, setNome] = useState('');
  const [formato, setFormato] = useState('pontos-corridos');
  const [qtdTimes, setQtdTimes] = useState(16);

  // 1. Buscando dados do Supabase
  const carregarCampeonatos = async () => {
    const { data, error } = await supabase
      .from('campeonatos')
      .select('*')
      .order('created_at', { ascending: false }); // Traz os mais recentes primeiro

    if (error) {
      console.error("Erro ao carregar do Supabase:", error);
    } else {
      setCampeonatos(data);
    }
  };

  useEffect(() => {
    carregarCampeonatos();
  }, []);

  // 2. Salvando dados no Supabase
  const criarCampeonatoReal = async (e) => {
    e.preventDefault();

    const { error } = await supabase
      .from('campeonatos')
      .insert([
        { nome: nome, formato: formato, qtd_times: qtdTimes }
      ]);

    if (error) {
      console.error("Erro ao criar:", error);
      alert("Erro ao salvar no banco!");
    } else {
      setNome('');
      setFormato('pontos-corridos');
      setQtdTimes(16);
      carregarCampeonatos();
      setView('home'); 
    }
  };

  return (
    <div className="min-h-screen bg-ef-dark text-white font-sans">
      <nav className="border-b border-gray-800 p-4 flex justify-between items-center bg-ef-card">
        <h1 
          className="text-2xl font-bold italic text-ef-green cursor-pointer" 
          onClick={() => setView('home')}
        >
          eFOOTBALL CHAMP
        </h1>
        <div className="space-x-6">
          <button onClick={() => setView('home')} className="hover:text-ef-green transition">Campeonatos</button>
          <button className="bg-ef-green text-black px-4 py-2 rounded-full font-bold hover:bg-green-400 transition">Entrar</button>
        </div>
      </nav>

      <main className="p-8 max-w-6xl mx-auto">
        
        {view === 'home' && (
          <>
            <header className="mb-10">
              <h2 className="text-4xl font-extrabold">Gerencie seus Torneios</h2>
              <p className="text-gray-400 mt-2">Crie tabelas, organize times e acompanhe resultados.</p>
            </header>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {/* Note que agora usamos champ.id (padrão do Supabase) ao invés de champ._id (MongoDB) */}
              {campeonatos.map((champ) => (
                <div key={champ.id} className="bg-ef-card p-6 rounded-2xl border border-gray-800 hover:border-ef-green transition-all cursor-pointer">
                  <div className="bg-ef-green text-black text-xs font-bold px-2 py-1 rounded inline-block mb-4">OPEN</div>
                  <h3 className="text-xl font-bold mb-2">{champ.nome}</h3>
                  <p className="text-gray-400 text-sm">{champ.qtd_times} Times • {champ.formato.replace('-', ' ')}</p>
                  <button className="mt-6 w-full py-2 border border-ef-green text-ef-green rounded-lg hover:bg-ef-green hover:text-black transition">Ver Tabela</button>
                </div>
              ))}
              
              <div 
                onClick={() => setView('criar')}
                className="border-2 border-dashed border-gray-800 p-6 rounded-2xl flex flex-col items-center justify-center text-gray-500 hover:text-ef-green hover:border-ef-green transition cursor-pointer"
              >
                 <span className="text-4xl mb-2">+</span>
                 <p className="font-bold">Criar Campeonato</p>
              </div>
            </div>
          </>
        )}

        {view === 'criar' && (
          <div className="max-w-2xl mx-auto bg-ef-card p-8 rounded-2xl border border-gray-800">
            <h2 className="text-3xl font-bold mb-6 border-b border-gray-800 pb-4">Novo Campeonato</h2>
            
            <form onSubmit={criarCampeonatoReal} className="space-y-6">
              <div>
                <label className="block text-gray-400 mb-2">Nome do Campeonato</label>
                <input 
                  type="text" 
                  required
                  value={nome}
                  onChange={(e) => setNome(e.target.value)}
                  className="w-full bg-ef-dark border border-gray-700 rounded-lg p-3 text-white focus:outline-none focus:border-ef-green transition"
                  placeholder="Ex: Copa eFootball Brasil"
                />
              </div>

              <div className="grid grid-cols-2 gap-6">
                <div>
                  <label className="block text-gray-400 mb-2">Formato</label>
                  <select 
                    value={formato}
                    onChange={(e) => setFormato(e.target.value)}
                    className="w-full bg-ef-dark border border-gray-700 rounded-lg p-3 text-white focus:outline-none focus:border-ef-green transition"
                  >
                    <option value="pontos-corridos">Pontos Corridos (Liga)</option>
                    <option value="mata-mata">Mata-Mata (Copa)</option>
                    <option value="grupos">Fase de Grupos</option>
                  </select>
                </div>

                <div>
                  <label className="block text-gray-400 mb-2">Quantidade de Times</label>
                  <input 
                    type="number" 
                    min="2"
                    max="64"
                    required
                    value={qtdTimes}
                    onChange={(e) => setQtdTimes(e.target.value)}
                    className="w-full bg-ef-dark border border-gray-700 rounded-lg p-3 text-white focus:outline-none focus:border-ef-green transition"
                  />
                </div>
              </div>

              <div className="flex space-x-4 pt-4">
                <button 
                  type="button" 
                  onClick={() => setView('home')}
                  className="flex-1 py-3 border border-gray-600 text-gray-400 rounded-lg hover:bg-gray-800 transition"
                >
                  Cancelar
                </button>
                <button 
                  type="submit" 
                  className="flex-1 py-3 bg-ef-green text-black font-bold rounded-lg hover:bg-green-400 transition"
                >
                  Salvar no Supabase
                </button>
              </div>

            </form>
          </div>
        )}

      </main>
    </div>
  );
}

export default App;
